// @ts-check
__card__({
  id: 'kanbanBugTriage',
  packId: 'kanban.v1',
  title: 'Bug Triage',
  icon: '🐞',
});

__doc__({
  name: 'kanbanBugTriage',
  summary: 'Four-lane bug triage desk with hot-issue highlights and a custom incident taxonomy.',
  tags: ['demo', 'kanban', 'bugs'],
  related: ['widgets.kanban.page', 'widgets.kanban.highlights', 'widgets.kanban.filters'],
});

doc`
---
symbol: kanbanBugTriage
---
This demo card uses the same board primitive but a different top section: a triage-oriented
highlight strip that calls out hot issues before the board itself.
`;

const bugTriageBoard = boardById('kanbanBugTriage');

defineRuntimeSurface(
  bugTriageBoard.id,
  ({ widgets }) => ({
    render({ state }) {
      const draft = boardDraft(state);
      return renderKanbanPage(widgets, bugTriageBoard, state, {
        highlightItems: [
          { id: 'hot', label: 'Hot', value: draft.tasks.filter((task) => task.priority === 'sev1').length, caption: 'Needs triage now', tone: 'danger', trend: [1, 1, 2, 4, 3, 3] },
          { id: 'queue', label: 'Queue', value: draft.tasks.length, caption: 'Across all lanes', tone: 'accent' },
          { id: 'verified', label: 'Verified', value: draft.tasks.filter((task) => task.col === 'verified').length, caption: 'Ready to close', tone: 'success', progress: 0.33 },
        ],
      });
    },
    handlers: kanbanCardHandlers(bugTriageBoard),
  }),
  'kanban.v1',
);

// @ts-check
__card__({
  id: 'kanbanIncidentCommand',
  packId: 'kanban.v1',
  title: 'Incident Command',
  icon: '🚨',
});

__doc__({
  name: 'kanbanIncidentCommand',
  summary: 'Three-lane incident command surface with telemetry highlights and custom status metrics.',
  tags: ['demo', 'kanban', 'incident'],
  related: ['widgets.kanban.page', 'widgets.kanban.highlights', 'widgets.kanban.status'],
});

doc`
---
symbol: kanbanIncidentCommand
---
This demo card shows the command-center end of the spectrum: telemetry highlights above a denser
three-lane board, still authored entirely with semantic Kanban primitives.
`;

const incidentCommandBoard = boardById('kanbanIncidentCommand');

defineRuntimeSurface(
  incidentCommandBoard.id,
  ({ widgets }) => ({
    render({ state }) {
      const draft = boardDraft(state);
      return renderKanbanPage(widgets, incidentCommandBoard, state, {
        emptyColumnMessage: 'No incidents here',
        dropHintMessage: 'Move incident',
        highlightItems: [
          { id: 'sev1', label: 'SEV-1', value: draft.tasks.filter((task) => task.priority === 'sev1').length, caption: 'Customer-visible outage', tone: 'danger', trend: [0, 1, 1, 2, 1, 1] },
          { id: 'mitigation', label: 'Mitigation', value: '74%', caption: 'Rollback progressing', tone: 'warning', progress: 0.74 },
          { id: 'latency', label: 'Latency', value: '182ms', caption: 'API p95', tone: 'accent', trend: [120, 140, 160, 210, 190, 182] },
        ],
        statusMetrics: [
          { label: 'open', value: draft.tasks.filter((task) => task.col !== 'resolved').length },
          { label: 'sev1', value: draft.tasks.filter((task) => task.priority === 'sev1').length },
          { label: 'customer', value: draft.tasks.filter((task) => task.labels.includes('customer')).length },
        ],
      });
    },
    handlers: kanbanCardHandlers(incidentCommandBoard),
  }),
  'kanban.v1',
);

// @ts-check
__card__({
  id: 'kanbanPersonalPlanner',
  packId: 'kanban.v1',
  title: 'Focus Inbox',
  icon: '🎯',
});

__doc__({
  name: 'kanbanPersonalPlanner',
  summary: 'Single-lane focus inbox demo using the compositional kanban.v1 page DSL.',
  tags: ['demo', 'kanban', 'personal'],
  related: ['widgets.kanban.page', 'widgets.kanban.header', 'widgets.kanban.highlights'],
});

doc`
---
symbol: kanbanPersonalPlanner
---
This demo card is intentionally minimal: one lane, no filter bar, and only a small focus-oriented
highlight strip above the board.
`;

const personalPlannerBoard = boardById('kanbanPersonalPlanner');

defineRuntimeSurface(
  personalPlannerBoard.id,
  ({ widgets }) => ({
    render({ state }) {
      return renderKanbanPage(widgets, personalPlannerBoard, state, {
        showFilters: false,
        highlightItems: [
          { id: 'energy', label: 'Energy', value: 'High', caption: 'Good time for deep work', tone: 'success' },
          { id: 'streak', label: 'Streak', value: '3 days', caption: 'Inbox under five cards', tone: 'accent', trend: [2, 3, 4, 4, 3, 5] },
        ],
        statusMetrics: [
          { label: 'captured', value: boardDraft(state).tasks.length },
          { label: 'mode', value: 'single-lane' },
        ],
      });
    },
    handlers: kanbanCardHandlers(personalPlannerBoard),
  }),
  'kanban.v1',
);

// @ts-check
__card__({
  id: 'kanbanReleaseTrain',
  packId: 'kanban.v1',
  title: 'Release Cutline',
  icon: '🚀',
});

__doc__({
  name: 'kanbanReleaseTrain',
  summary: 'Two-lane release cutline board with launch highlights and custom release taxonomy.',
  tags: ['demo', 'kanban', 'release'],
  related: ['widgets.kanban.page', 'widgets.kanban.highlights', 'widgets.kanban.taxonomy'],
});

doc`
---
symbol: kanbanReleaseTrain
---
This demo card is intentionally narrow: just two lanes, no filters, and a small launch cutline
summary that makes the board feel very different from the sprint or incident examples.
`;

const releaseTrainBoard = boardById('kanbanReleaseTrain');

defineRuntimeSurface(
  releaseTrainBoard.id,
  ({ widgets }) => ({
    render({ state }) {
      const draft = boardDraft(state);
      return renderKanbanPage(widgets, releaseTrainBoard, state, {
        showFilters: false,
        title: 'Release Cutline / Q2',
        subtitle: 'Launch gates, blockers, and rollout checks.',
        highlightItems: [
          { id: 'readiness', label: 'Readiness', value: '82%', caption: 'Across platform gates', tone: 'success', progress: 0.82 },
          { id: 'blockers', label: 'Blockers', value: draft.tasks.filter((task) => task.priority === 'blocker').length, caption: 'Holding the cut', tone: 'danger' },
        ],
        statusMetrics: [
          { label: 'gates', value: draft.tasks.filter((task) => task.col === 'gated').length },
          { label: 'shipping', value: draft.tasks.filter((task) => task.col === 'shipping').length },
          { label: 'blockers', value: draft.tasks.filter((task) => task.priority === 'blocker').length },
        ],
      });
    },
    handlers: kanbanCardHandlers(releaseTrainBoard),
  }),
  'kanban.v1',
);

// @ts-check
__card__({
  id: 'kanbanSprintBoard',
  packId: 'kanban.v1',
  title: 'Sprint Board',
  icon: '🏁',
});

__doc__({
  name: 'kanbanSprintBoard',
  summary: 'Five-lane sprint radar demo for the compositional kanban.v1 page DSL.',
  tags: ['demo', 'kanban', 'sprint'],
  related: ['widgets.kanban.page', 'widgets.kanban.highlights', 'widgets.kanban.board'],
});

doc`
---
symbol: kanbanSprintBoard
---
This demo card uses the page-style DSL to build a denser sprint radar with an idea lane and a
summary highlight strip above the board.
`;

const sprintBoard = boardById('kanbanSprintBoard');

defineRuntimeSurface(
  sprintBoard.id,
  ({ widgets }) => ({
    render({ state }) {
      const draft = boardDraft(state);
      return renderKanbanPage(widgets, sprintBoard, state, {
        highlightItems: [
          { id: 'committed', label: 'Committed', value: '34 pts', caption: 'Sprint 12', tone: 'accent', trend: [22, 24, 26, 29, 31, 34] },
          { id: 'blocked', label: 'Blocked', value: draft.tasks.filter((task) => task.priority === 'high').length, caption: 'Need review attention', tone: 'warning', progress: 0.22 },
          { id: 'done', label: 'Done', value: draft.tasks.filter((task) => task.col === 'done').length, caption: 'Already shipped', tone: 'success', progress: 0.61 },
        ],
      });
    },
    handlers: kanbanCardHandlers(sprintBoard),
  }),
  'kanban.v1',
);
